local folder = workspace:FindFirstChild("Builds") or Instance.new("Folder",workspace)
folder.Name = "Builds"

for _,v in pairs(partTable) do
    local ok,tpl = pcall(function()
        return game.ReplicatedStorage.ClientItemInfo:FindFirstChild(v.Name):FindFirstChildOfClass('Model')
    end)
    if ok and tpl then
        local part = tpl:Clone()
        part.Parent = folder
        part:SetPrimaryPartCFrame(v.CFrame)
        part.Name = v.Name
        local tv = Instance.new("StringValue",part)
        tv.Name = "TreeValue"
        tv.Value = v.TreeValue
        for _,wp in pairs(part:GetDescendants()) do
            if wp.Name:find("BuildDependent") and wp:IsA("BasePart") then
                local c = v.TreeValue
                if     c=="Generic"     then wp.Color=Color3.fromRGB(204,142,105)
                elseif c=="Oak"         then wp.Color=Color3.fromRGB(234,184,146)
                elseif c=="Cherry"      then wp.Color=Color3.fromRGB(163,75,75)
                elseif c=="Fir"         then wp.Color=Color3.fromRGB(215,197,154)
                elseif c=="Birch"       then wp.Color=Color3.fromRGB(205,205,205)
                elseif c=="Walnut"      then wp.Color=Color3.fromRGB(105,64,40)
                elseif c=="Koa"         then wp.Color=Color3.fromRGB(143,76,42)
                elseif c=="Volcano"     then wp.Color=Color3.fromRGB(255,0,0)
                elseif c=="GreenSwampy" then wp.Color=Color3.fromRGB(52,142,64)
                elseif c=="GoldSwampy"  then wp.Color=Color3.fromRGB(226,155,64)
                elseif c=="Palm"        then wp.Color=Color3.fromRGB(226,220,188)
                elseif c=="SnowGlow"    then wp.Color=Color3.fromRGB(255,255,0)
                elseif c=="Frost"       then wp.Color=Color3.fromRGB(159,243,233)
                elseif c=="CaveCrawler" then wp.Color=Color3.fromRGB(16,42,220)
                elseif c=="BlueSpruce"  then wp.Color=Color3.fromRGB(159,173,192)
                elseif c=="LoneCave"    then wp.Color=Color3.fromRGB(248,248,248)
                elseif c=="Spooky" then
                    wp.Material=Enum.Material.Granite
                    wp.Color=Color3.fromRGB(170,85,0)
                end
            end
        end
        for _,p in pairs(part:GetDescendants()) do
            if p:IsA('BasePart') then p.Anchored=true p.CanCollide=false end
        end
    end
end
